pub fn dec_url(s: &str) -> Option<Vec<u8>> {
    use base64::{engine::general_purpose::URL_SAFE_NO_PAD, Engine};
    URL_SAFE_NO_PAD.decode(s).ok()
}

pub fn parse_hex(s: &str) -> Vec<u8> {
    hex::decode(s).unwrap_or_default()
}

pub fn check_scheme(uri: &str) -> bool {
    let parsed: Result<http::Uri, _> = uri.parse();
    matches!(parsed.map(|u| u.scheme_str().map(str::to_string)), Ok(Some(ref s)) if s == "https")
}

